// Script: generar_117_estabilizar_base.js
// Estabilizacion completa antes de nuevas funcionalidades.
// Resuelve 4 regresiones en 7 archivos:
//
// 1) ESTERILIZADO/A EN PERFIL (app/perfil/page.tsx)
//    Antes decia "Castrado" y "Si/No". Ahora dice "Esterilizado/a"
//    o "Entero/a" con label "Estado". Consistente con el Dashboard.
//
// 2) SCROLL MODAL + BOTTOMNAV (app/prevencion/page.tsx)
//    El modal quedaba tapado por el BottomNav. Fix definitivo:
//    overflow-hidden en backdrop + maxHeight: calc(100vh - 80px)
//    en el contenido. Ya aplicado en el script anterior, se mantiene.
//
// 3) SELECTOR DE FECHA AÑO/MES/DÍA (components/FechaSelector.tsx NUEVO)
//    Reemplaza el input type="date" nativo (calendario de Android que
//    obliga a navegar mes a mes). El nuevo selector muestra primero
//    el año, luego el mes, luego el día — mucho más rápido para
//    registrar vacunas antiguas o cargar historiales completos.
//    Se usa en Prevención y Reproducción. Reutilizable en cualquier
//    formulario de la app.
//
// 4) REPRODUCCIÓN CON SELECTOR DE FECHA
//    Los modales de ciclo y etapa ahora también usan FechaSelector
//    en vez del input nativo.

const fs = require('fs'); const path = require('path');
function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64,'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir,{recursive:true});
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}
escribir('components/FechaSelector.tsx', "");
escribir('app/prevencion/page.tsx', "");
escribir('app/perfil/page.tsx', "");
escribir('components/ReproduccionTracker.tsx', "");
escribir('components/RespiracionTracker.tsx', "");
escribir('app/vet/page.tsx', "");
escribir('app/analisis/page.tsx', "");
escribir('app/dashboard/page.tsx', "");
